import React, { useState } from "react";
import './Logout.css';
import './Welcome';
import { useNavigate } from "react-router";
import axios from "axios";
function Logout () {
    const [response, setResponse] = useState([]); 
    const navigate = useNavigate();
    const GetCall = (prop) => {
       axios.get(`http://localhost:8080/user/${prop.userName}/items`).then(response => console.log(response.data))
    //    console.log(response)
    }
    const viewData = () => {
        return () => GetCall()
    }
    return <div className="nav-bar">
    <div className="header">
    <a href="#default" className="logo">Productiv</a>
    <div className="header-right">
    <a href="#home" onClick={() => viewData}>My Account</a>
    <a href="#contact" onClick={() => navigate('/')} >Logout</a>
  </div>
    </div>
        <h1>Welcome!</h1>
    </div>
}

export default Logout;
